1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function countByType(items: any[]): Record<string, number> {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] ?? 0) + 1;
21	  }
22	  return counts;
23	}
24	
25	function calculateBasePremium(typeCounts: Record<string, number>): number {
26	  let total = 0;
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
29	      total += BLOCK_PREMIUM;
30	    } else {
31	      total += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	  return total;
35	}
36	
37	const CURSED_SURCHARGE_RATE = 0.5;
38	
39	function calculateItemSurcharges(items: any[]): number {
40	  return items
41	    .filter((item: any) => item.cursed)
42	    .reduce((total: number, item: any) => total + (BASE_PREMIUM[item.type] ?? 0) * CURSED_SURCHARGE_RATE, 0);
43	}
44	
45	function calculateQuotePremium(items: any[]): number {
46	  const typeCounts = countByType(items);
47	  const basePremium = calculateBasePremium(typeCounts);
48	  const itemSurcharges = calculateItemSurcharges(items);
49	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
50	  return Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
51	}
52	
53	export function processScenario(scenario: any): unknown {
54	  const results = scenario.steps.map((step: any) => ({
55	    premium: calculateQuotePremium(step.items),
56	  }));
57	
58	  return { results };
59	}
